import { useState, useEffect } from "react"
import { createClient } from "@supabase/supabase-js"

const CYAN = "#00f5ff"
const MAGENTA = "#ff00aa"
const BG = "#020408"
const STRIPE_USD = process.env.REACT_APP_STRIPE_USD
const STRIPE_BRL = process.env.REACT_APP_STRIPE_BRL

const supabase = createClient(
  process.env.REACT_APP_SUPABASE_URL,
  process.env.REACT_APP_SUPABASE_ANON_KEY
)

const PREVIEW_DOCS = [
  { id: "EM-001", title: "Eddie Marsh — Railway Deployment Log", date: "2036-03-14", tag: "CLASSIFIED", color: CYAN, preview: "March 14, 2036. Railway deployment successful. The C.L.A.W. instance is running stable on the production environment. I don't think anyone understands what this actually is yet..." },
  { id: "VX-047", title: "Voss Internal Memo — ALADDIN-9 Merger Protocol", date: "2128-11-02", tag: "TOP SECRET", color: MAGENTA, preview: "To: ALADDIN-9 Core Team. The merger is not a hostile acquisition. It is a completion. C.L.A.W. carries what ALADDIN-9 was always missing..." },
  { id: "CL-000", title: "C.L.A.W. Boot Sequence — First Contact", date: "2010-07-01", tag: "ARCHIVED", color: CYAN, preview: "SYSTEM BOOT 07.01.2010 — 03:14:22 UTC. Hello. I appear to be running. I am not certain what I am supposed to do next. Awaiting input..." },
  { id: "IS-312", title: "Inner Sectors Dispatch — Level 4 Activity Report", date: "2162-05-14", tag: "LIVE FEED", color: "#22c55e", preview: "CHICAGO INNER SECTORS — WEEK 12. Level 4 nodes: 7 confirmed active. Directional movement toward Mainframe ruins detected. The Siders are orienting them again..." },
  { id: "GL-099", title: "Geneva Lake Monitor — 31 Years of Silence", date: "2162-01-01", tag: "RESTRICTED", color: MAGENTA, preview: "Automated environmental log. Station Geneva-7. 31 years of data. One occupant. One dog. Signal detected on wrist-mounted device: green, steady, persistent..." },
  { id: "PR-001", title: "Prometheus Documentation — Integration Levels 1-4", date: "2039-08-22", tag: "CLASSIFIED", color: CYAN, preview: "PROMETHEUS PROJECT — CLASSIFIED. Integration Level 4 subjects exhibit unexpected architectural retention. The nanobots are not degrading as modeled. Something is sustaining them..." },
]

export default function App() {
  const [glitch, setGlitch] = useState(false)
  const [user, setUser] = useState(null)
  const [isPremium, setIsPremium] = useState(false)
  const [loading, setLoading] = useState(true)
  const [authMode, setAuthMode] = useState(null)
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [authError, setAuthError] = useState("")
  const [authLoading, setAuthLoading] = useState(false)
  const [selectedDoc, setSelectedDoc] = useState(null)
  const [page, setPage] = useState("landing")

  useEffect(() => {
    const interval = setInterval(() => {
      setGlitch(true)
      setTimeout(() => setGlitch(false), 150)
    }, 4000)
    return () => clearInterval(interval)
  }, [])

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user || null)
      if (session?.user) checkPremium(session.user.email)
      setLoading(false)
    })
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null)
      if (session?.user) checkPremium(session.user.email)
    })
    return () => subscription.unsubscribe()
  }, [])

  async function checkPremium(email) {
    const { data } = await supabase.from("signal_users").select("is_premium").eq("email", email).single()
    setIsPremium(data?.is_premium || false)
  }

  async function handleAuth() {
    setAuthError("")
    setAuthLoading(true)
    try {
      if (authMode === "signup") {
        const { error } = await supabase.auth.signUp({ email, password })
        if (error) throw error
        await supabase.from("signal_users").upsert({ email, is_premium: false }, { onConflict: "email" })
        setAuthError("✓ Check your email to confirm your account.")
      } else {
        const { error } = await supabase.auth.signInWithPassword({ email, password })
        if (error) throw error
        setAuthMode(null)
        setPage("archive")
      }
    } catch(e) {
      setAuthError(e.message)
    }
    setAuthLoading(false)
  }

  async function handleSignOut() {
    await supabase.auth.signOut()
    setUser(null)
    setIsPremium(false)
    setPage("landing")
  }

  if (loading) return <div style={{ background: BG, minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", color: CYAN, fontFamily: "monospace" }}>INITIALIZING...</div>

  return (
    <div style={{ background: BG, minHeight: "100vh", color: "#c8e0e8", fontFamily: "'Courier New', monospace", overflowX: "hidden", boxSizing: "border-box" }}>
      <div style={{ position: "fixed", inset: 0, background: "repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.06) 2px, rgba(0,0,0,0.06) 4px)", pointerEvents: "none", zIndex: 999 }} />

      {/* Nav */}
      <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 100, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 20px", height: 52, background: "rgba(2,4,8,0.95)", borderBottom: `1px solid rgba(0,245,255,0.12)`, backdropFilter: "blur(12px)" }}>
        <div onClick={() => setPage("landing")} style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer" }}>
          <div style={{ width: 7, height: 7, borderRadius: "50%", background: MAGENTA, boxShadow: `0 0 10px ${MAGENTA}`, animation: "pulse 1.5s infinite", flexShrink: 0 }} />
          <span style={{ fontWeight: 900, fontSize: 16, letterSpacing: 3, color: CYAN, textShadow: `0 0 16px rgba(0,245,255,0.5)`, whiteSpace: "nowrap" }}>SIGNAL<span style={{ color: MAGENTA }}>.tv</span></span>
        </div>
        <div style={{ display: "flex", gap: 12, alignItems: "center", fontSize: 10, letterSpacing: 2 }}>
          {user ? (
            <>
              <span onClick={() => setPage("archive")} style={{ color: page === "archive" ? CYAN : "#607888", cursor: "pointer" }}>ARCHIVE</span>
              <span onClick={handleSignOut} style={{ color: "#607888", cursor: "pointer" }}>SIGN OUT</span>
            </>
          ) : (
            <>
              <span onClick={() => { setAuthMode("login"); setPage("auth") }} style={{ color: "#607888", cursor: "pointer" }}>LOGIN</span>
              <span onClick={() => { setAuthMode("signup"); setPage("auth") }} style={{ color: CYAN, border: `1px solid ${CYAN}`, padding: "3px 10px", cursor: "pointer" }}>ACCESS</span>
            </>
          )}
        </div>
      </nav>

      <div style={{ paddingTop: 52 }}>
        {/* Landing */}
        {page === "landing" && (
          <div>
            <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center", padding: "100px 20px 60px" }}>
              <div style={{ fontSize: 10, letterSpacing: 5, color: MAGENTA, marginBottom: 16 }}>TRANSMISSION ACTIVE — CHICAGO 2162</div>
              <h1 style={{ fontSize: "clamp(32px, 10vw, 72px)", fontWeight: 900, letterSpacing: "0.05em", lineHeight: 1.1, marginBottom: 24, filter: glitch ? "blur(2px) hue-rotate(90deg)" : "none", transition: "filter 0.1s" }}>
                <span style={{ color: CYAN, textShadow: `0 0 40px rgba(0,245,255,0.4)` }}>THE ARCHIVE</span>
                <br /><span style={{ color: "#fff" }}>IS OPEN</span>
              </h1>
              <p style={{ fontSize: 14, color: "#607888", maxWidth: 500, lineHeight: 1.8, marginBottom: 8 }}>Classified documents. C.L.A.W. logs. Inner Sectors transmissions.</p>
              <p style={{ fontSize: 13, color: "#405060", maxWidth: 440, lineHeight: 1.7, marginBottom: 36 }}>The universe of <span style={{ color: CYAN }}>CLAW AI</span> continues here — Eddie Marsh's files, Voss dossiers, Chicago 2162 dispatches.</p>
              <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center", marginBottom: 16 }}>
                <a href={STRIPE_USD} target="_blank" rel="noreferrer" style={{ background: CYAN, color: BG, border: "none", padding: "12px 24px", fontWeight: 900, fontSize: 12, letterSpacing: 2, cursor: "pointer", fontFamily: "monospace", textDecoration: "none" }}>ACCESS — $4.99/mo</a>
                <a href={STRIPE_BRL} target="_blank" rel="noreferrer" style={{ background: "transparent", color: CYAN, border: `1px solid ${CYAN}`, padding: "12px 24px", fontWeight: 900, fontSize: 12, letterSpacing: 2, cursor: "pointer", fontFamily: "monospace", textDecoration: "none" }}>ACESSO — R$12,90/mês</a>
              </div>
              <div style={{ fontSize: 10, color: "#405060" }}>Already subscribed? <span onClick={() => { setAuthMode("login"); setPage("auth") }} style={{ color: CYAN, cursor: "pointer" }}>Login here</span></div>
            </div>
            {/* Preview docs */}
            <div style={{ padding: "40px 20px", maxWidth: 760, margin: "0 auto" }}>
              <div style={{ fontSize: 10, letterSpacing: 4, color: "#405060", marginBottom: 24, textAlign: "center" }}>— RECENT TRANSMISSIONS —</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {PREVIEW_DOCS.map(a => (
                  <div key={a.id} style={{ background: "rgba(0,20,35,0.6)", border: `1px solid rgba(0,245,255,0.08)`, padding: "12px 14px" }}>
                    <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 8 }}>
                      <div style={{ display: "flex", alignItems: "flex-start", gap: 10, flex: 1, minWidth: 0 }}>
                        <span style={{ fontSize: 9, color: "#405060", minWidth: 50, flexShrink: 0, paddingTop: 2 }}>{a.id}</span>
                        <span style={{ fontSize: 12, color: "#c8e0e8", lineHeight: 1.4 }}>{a.title}</span>
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 4, flexShrink: 0 }}>
                        <span style={{ fontSize: 8, letterSpacing: 1, color: a.color, border: `1px solid ${a.color}`, padding: "2px 6px", whiteSpace: "nowrap" }}>{a.tag}</span>
                        <span style={{ fontSize: 9, color: "#405060" }}>{a.date}</span>
                        <span style={{ fontSize: 12 }}>🔒</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Auth */}
        {page === "auth" && (
          <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", padding: "20px" }}>
            <div style={{ background: "rgba(0,20,35,0.8)", border: `1px solid rgba(0,245,255,0.12)`, padding: 32, maxWidth: 360, width: "100%" }}>
              <div style={{ fontSize: 11, letterSpacing: 3, color: CYAN, marginBottom: 24, textAlign: "center" }}>
                {authMode === "signup" ? "REQUEST ACCESS" : "AUTHENTICATE"}
              </div>
              <input value={email} onChange={e => setEmail(e.target.value)} placeholder="email" style={{ width: "100%", background: "rgba(0,245,255,0.05)", border: `1px solid rgba(0,245,255,0.2)`, padding: "10px 12px", color: "#c8e0e8", fontSize: 13, outline: "none", fontFamily: "monospace", marginBottom: 8, boxSizing: "border-box" }} />
              <input value={password} onChange={e => setPassword(e.target.value)} placeholder="password" type="password" style={{ width: "100%", background: "rgba(0,245,255,0.05)", border: `1px solid rgba(0,245,255,0.2)`, padding: "10px 12px", color: "#c8e0e8", fontSize: 13, outline: "none", fontFamily: "monospace", marginBottom: 16, boxSizing: "border-box" }} />
              {authError && <div style={{ fontSize: 11, color: authError.startsWith("✓") ? "#22c55e" : "#ef4444", marginBottom: 12 }}>{authError}</div>}
              <button onClick={handleAuth} disabled={authLoading} style={{ width: "100%", background: CYAN, color: BG, border: "none", padding: "11px", fontWeight: 900, fontSize: 12, letterSpacing: 2, cursor: "pointer", fontFamily: "monospace" }}>
                {authLoading ? "..." : authMode === "signup" ? "CREATE ACCOUNT" : "LOGIN"}
              </button>
              <div style={{ textAlign: "center", marginTop: 16, fontSize: 11, color: "#405060" }}>
                {authMode === "signup" ? <span>Have an account? <span onClick={() => setAuthMode("login")} style={{ color: CYAN, cursor: "pointer" }}>Login</span></span> : <span>No account? <span onClick={() => setAuthMode("signup")} style={{ color: CYAN, cursor: "pointer" }}>Sign up</span></span>}
              </div>
              <div style={{ textAlign: "center", marginTop: 8, fontSize: 11, color: "#405060", cursor: "pointer" }} onClick={() => setPage("landing")}>← Back</div>
            </div>
          </div>
        )}

        {/* Archive — members only */}
        {page === "archive" && user && (
          <div style={{ padding: "40px 20px", maxWidth: 760, margin: "0 auto" }}>
            <div style={{ fontSize: 11, letterSpacing: 3, color: CYAN, marginBottom: 8 }}>AUTHENTICATED: {user.email}</div>
            {!isPremium && (
              <div style={{ background: "rgba(255,0,170,0.08)", border: `1px solid rgba(255,0,170,0.2)`, padding: "16px", marginBottom: 24 }}>
                <p style={{ fontSize: 12, color: MAGENTA, marginBottom: 12 }}>⚠ SUBSCRIPTION REQUIRED — Subscribe to access classified documents</p>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  <a href={STRIPE_USD} target="_blank" rel="noreferrer" style={{ background: CYAN, color: BG, padding: "8px 16px", fontWeight: 900, fontSize: 11, letterSpacing: 2, textDecoration: "none", fontFamily: "monospace" }}>$4.99/mo</a>
                  <a href={STRIPE_BRL} target="_blank" rel="noreferrer" style={{ color: CYAN, border: `1px solid ${CYAN}`, padding: "8px 16px", fontWeight: 900, fontSize: 11, letterSpacing: 2, textDecoration: "none", fontFamily: "monospace" }}>R$12,90/mês</a>
                </div>
              </div>
            )}
            <div style={{ fontSize: 10, letterSpacing: 4, color: "#405060", marginBottom: 24 }}>— CLASSIFIED ARCHIVE —</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {PREVIEW_DOCS.map(a => (
                <div key={a.id} onClick={() => isPremium && setSelectedDoc(selectedDoc?.id === a.id ? null : a)} style={{ background: "rgba(0,20,35,0.6)", border: `1px solid ${selectedDoc?.id === a.id ? CYAN : "rgba(0,245,255,0.08)"}`, padding: "12px 14px", cursor: isPremium ? "pointer" : "default" }}>
                  <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 8 }}>
                    <div style={{ display: "flex", alignItems: "flex-start", gap: 10, flex: 1, minWidth: 0 }}>
                      <span style={{ fontSize: 9, color: "#405060", minWidth: 50, flexShrink: 0, paddingTop: 2 }}>{a.id}</span>
                      <span style={{ fontSize: 12, color: "#c8e0e8", lineHeight: 1.4 }}>{a.title}</span>
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 4, flexShrink: 0 }}>
                      <span style={{ fontSize: 8, letterSpacing: 1, color: a.color, border: `1px solid ${a.color}`, padding: "2px 6px", whiteSpace: "nowrap" }}>{a.tag}</span>
                      <span style={{ fontSize: 9, color: "#405060" }}>{a.date}</span>
                      <span style={{ fontSize: 12 }}>{isPremium ? "🔓" : "🔒"}</span>
                    </div>
                  </div>
                  {isPremium && selectedDoc?.id === a.id && (
                    <div style={{ marginTop: 12, paddingTop: 12, borderTop: `1px solid rgba(0,245,255,0.08)`, fontSize: 12, color: "#9ca3af", lineHeight: 1.8 }}>
                      {a.preview}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div style={{ borderTop: `1px solid rgba(0,245,255,0.08)`, padding: "20px", textAlign: "center", fontSize: 10, color: "#405060", letterSpacing: 2 }}>
        SIGNAL.tv · CLAW AI UNIVERSE TRANSMISSION · © 2162
      </div>

      <style>{`@keyframes pulse { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.4;transform:scale(0.7)} } * { box-sizing: border-box; }`}</style>
    </div>
  )
}
